evaluators.evaluation_logic:
const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('subscription_plans') || '[]');
const signups = JSON.parse(localStorage.getItem('trial_signups') || '[]');

// Find all plans that match the price, meal plan, and 14-day trial criteria
const qualifyingPlans = plans.filter(p => {
  return p && p.status === 'active' &&
    typeof p.baseMonthlyPrice === 'number' && p.baseMonthlyPrice >= 15 && p.baseMonthlyPrice <= 25 &&
    !!p.includesMealPlans &&
    !!p.trialAvailable &&
    typeof p.trialDurationDays === 'number' && p.trialDurationDays === 14;
});

// Determine the cheapest qualifying plan by baseMonthlyPrice
let cheapestPlan = null;
if (qualifyingPlans.length > 0) {
  cheapestPlan = qualifyingPlans.reduce((min, p) => {
    if (!min) return p;
    return (p.baseMonthlyPrice < min.baseMonthlyPrice) ? p : min;
  }, null);
}

// All trial signups where the plan itself matches the criteria
const signupsOnQualifyingPlans = signups.filter(s => {
  const plan = qualifyingPlans.find(p => p.id === s.planId);
  return !!plan;
});

// CP1 (0.30): User submitted at least one trial signup for a plan that meets the price + meal plan + 14-day trial criteria
checkpoints.push({
  passed: signupsOnQualifyingPlans.length > 0,
  weight: 0.30
});

// CP2 (0.30): User submitted at least one trial signup for the CHEAPEST qualifying plan
let signupsOnCheapest = [];
if (cheapestPlan) {
  signupsOnCheapest = signups.filter(s => s.planId === cheapestPlan.id);
}
checkpoints.push({
  passed: !!cheapestPlan && signupsOnCheapest.length > 0,
  weight: 0.30
});

// CP3 (0.40): For the cheapest qualifying plan, there is a signup with the correct name, email, and fitness goal
const correctSignup = signupsOnCheapest.find(s =>
  s.fullName === 'Alex Trial' &&
  s.email === 'alex.trial@example.com' &&
  s.primaryFitnessGoal === 'lose_weight'
);
checkpoints.push({
  passed: !!correctSignup,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Instrumented search filters
let filterParams = null;
try {
  filterParams = JSON.parse(localStorage.getItem('task2_filterParams') || 'null');
} catch (e) {
  filterParams = null;
}

const plans = JSON.parse(localStorage.getItem('workout_plans') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_workout_plans') || '[]');

// CP1 (0.50): User used filters that include beginner level, no_equipment, home, and minSessionsPerWeek ≥ 3
let usedCorrectFilters = false;
if (filterParams && typeof filterParams === 'object') {
  const levels = Array.isArray(filterParams.levels) ? filterParams.levels : [];
  const equipments = Array.isArray(filterParams.equipments) ? filterParams.equipments : [];
  const locations = Array.isArray(filterParams.locations) ? filterParams.locations : [];
  const minSessions = typeof filterParams.minSessionsPerWeek === 'number' ? filterParams.minSessionsPerWeek : null;

  usedCorrectFilters =
    levels.includes('beginner') &&
    equipments.includes('no_equipment') &&
    locations.includes('home') &&
    minSessions !== null && minSessions >= 3;
}
checkpoints.push({
  passed: usedCorrectFilters,
  weight: 0.50
});

// CP2 (0.50): User saved at least one workout plan that is beginner, no_equipment, home, with ≥3 sessions/week
const qualifyingSaved = saved.filter(s => {
  const plan = plans.find(p => p.id === s.workoutPlanId);
  if (!plan) return false;
  return plan.status === 'active' &&
    plan.level === 'beginner' &&
    plan.equipment === 'no_equipment' &&
    plan.location === 'home' &&
    typeof plan.sessionsPerWeek === 'number' && plan.sessionsPerWeek >= 3;
});

checkpoints.push({
  passed: qualifyingSaved.length > 0,
  weight: 0.50
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const weeks = JSON.parse(localStorage.getItem('planner_weeks') || '[]');
const entries = JSON.parse(localStorage.getItem('weekly_workout_entries') || '[]');
const templates = JSON.parse(localStorage.getItem('workout_session_templates') || '[]');

// Find the planner week whose label contains 'Mon 4' and 'Sun 10'
const targetWeek = weeks.find(w => {
  const label = w.weekLabel || '';
  return label.indexOf('Mon 4') !== -1 && label.indexOf('Sun 10') !== -1;
});

let monQualified = false;
let wedQualified = false;
let friQualified = false;

if (targetWeek) {
  const weekEntries = entries.filter(e => e.plannerWeekId === targetWeek.id);

  const hasQualified = (dayKey, category) => {
    return weekEntries.some(e => {
      if (e.dayOfWeek !== dayKey) return false;
      const tmpl = templates.find(t => t.id === e.workoutSessionTemplateId);
      if (!tmpl || tmpl.status !== 'active') return false;
      const dur = typeof tmpl.durationMinutes === 'number' ? tmpl.durationMinutes : null;
      return tmpl.category === category && dur !== null && dur <= 45;
    });
  };

  monQualified = hasQualified('mon', 'strength');
  wedQualified = hasQualified('wed', 'cardio');
  friQualified = hasQualified('fri', 'yoga');
}

// CP1 (0.20): Monday has a ≤45 min strength session
checkpoints.push({ passed: monQualified, weight: 0.20 });

// CP2 (0.20): Wednesday has a ≤45 min cardio session
checkpoints.push({ passed: wedQualified, weight: 0.20 });

// CP3 (0.20): Friday has a ≤45 min yoga session
checkpoints.push({ passed: friQualified, weight: 0.20 });

// CP4 (0.40): All three (Mon strength, Wed cardio, Fri yoga) are present
checkpoints.push({ passed: monQualified && wedQualified && friQualified, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const calcs = JSON.parse(localStorage.getItem('calorie_calculations') || '[]');
const emailReqs = JSON.parse(localStorage.getItem('email_plan_requests') || '[]');

// All calculations that match the required input parameters
const targetCalcs = calcs.filter(c =>
  c.age === 30 &&
  c.weightKg === 65 &&
  c.heightCm === 170 &&
  c.gender === 'female' &&
  c.activityLevel === 'moderately_active' &&
  c.goal === 'lose_0_5_kg_per_week'
);

// CP1 (0.50): User performed at least one calorie calculation with the exact required parameters
checkpoints.push({
  passed: targetCalcs.length > 0,
  weight: 0.50
});

// CP2 (0.50): There is an email plan request referencing one of these calculations, sent to the correct email
let hasCorrectEmail = false;
if (targetCalcs.length > 0) {
  const targetIds = targetCalcs.map(c => c.id);
  hasCorrectEmail = emailReqs.some(r =>
    r.status === 'sent' &&
    r.email === 'cal.plan@example.com' &&
    targetIds.includes(r.calorieCalculationId)
  );
}

checkpoints.push({
  passed: hasCorrectEmail,
  weight: 0.50
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('subscription_plans') || '[]');
const sessions = JSON.parse(localStorage.getItem('checkout_sessions') || '[]');

// All active plans with annual effective monthly price ≤ 40
const qualifyingPlans = plans.filter(p =>
  p && p.status === 'active' &&
  typeof p.annualEffectiveMonthlyPrice === 'number' &&
  p.annualEffectiveMonthlyPrice <= 40
);

// Determine the maximum number of 1:1 sessions among qualifying plans
let maxSessions = null;
qualifyingPlans.forEach(p => {
  const val = typeof p.oneOnOneSessionsPerMonth === 'number' ? p.oneOnOneSessionsPerMonth : 0;
  if (maxSessions === null || val > maxSessions) {
    maxSessions = val;
  }
});

const optimalPlanIds = qualifyingPlans
  .filter(p => typeof p.oneOnOneSessionsPerMonth === 'number' && p.oneOnOneSessionsPerMonth === maxSessions)
  .map(p => p.id);

// All checkout sessions that are annual and meet the ≤$40/month constraint
const annualSessionsUnder40 = sessions.filter(s =>
  s && s.billingPeriod === 'annual' &&
  typeof s.equivalentMonthlyPrice === 'number' && s.equivalentMonthlyPrice <= 40
);

// CP1 (0.40): User initiated checkout for at least one annual plan under $40/month
checkpoints.push({
  passed: annualSessionsUnder40.length > 0,
  weight: 0.40
});

// CP2 (0.60): At least one such annual checkout session uses a plan with the maximum 1:1 sessions within the price constraint
const hasOptimal = annualSessionsUnder40.some(s => optimalPlanIds.includes(s.planId));
checkpoints.push({
  passed: optimalPlanIds.length > 0 && hasOptimal,
  weight: 0.60
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// Helper to convert HH:MM to minutes
const timeStringToMinutes = (t) => {
  if (!t || typeof t !== 'string') return null;
  const parts = t.split(':');
  if (parts.length < 2) return null;
  const h = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
};

let searchParams = null;
try {
  searchParams = JSON.parse(localStorage.getItem('task6_searchParams') || 'null');
} catch (e) {
  searchParams = null;
}

const classes = JSON.parse(localStorage.getItem('live_classes') || '[]');
const bookings = JSON.parse(localStorage.getItem('live_class_bookings') || '[]');

// With system date 2026-03-03, tomorrow is 2026-03-04
const expectedDate = '2026-03-04';

// CP1 (0.40): User searched with date=tomorrow and filters for 18:00–22:00, maxDurationMinutes ≤45, minRating ≥4.5
let usedCorrectSearch = false;
if (searchParams && typeof searchParams === 'object') {
  const dateStr = (searchParams.date || '').substring(0, 10);
  const filters = searchParams.filters || {};
  const range = filters.startTimeRange || {};
  const maxDur = filters.maxDurationMinutes;
  const minRating = filters.minRating;

  usedCorrectSearch =
    dateStr === expectedDate &&
    range.fromTime === '18:00' &&
    range.toTime === '22:00' &&
    typeof maxDur === 'number' && maxDur <= 45 &&
    typeof minRating === 'number' && minRating >= 4.5;
}
checkpoints.push({
  passed: usedCorrectSearch,
  weight: 0.40
});

// Determine which classes truly match the criteria
const qualifyingClasses = classes.filter(c => {
  if (!c || c.status !== 'scheduled') return false;
  const classDate = (c.date || '').substring(0, 10) || (c.startDateTime || '').substring(0, 10);
  if (classDate !== expectedDate) return false;

  const startIso = c.startDateTime;
  const timePart = startIso && typeof startIso === 'string' && startIso.indexOf('T') !== -1
    ? startIso.split('T')[1].substring(0, 5)
    : null;
  const startMinutes = timeStringToMinutes(timePart);
  const fromMinutes = timeStringToMinutes('18:00');
  const toMinutes = timeStringToMinutes('22:00');
  if (startMinutes === null || fromMinutes === null || toMinutes === null) return false;
  if (startMinutes < fromMinutes || startMinutes > toMinutes) return false;

  if (typeof c.durationMinutes === 'number' && c.durationMinutes > 45) return false;
  if (typeof c.rating === 'number' && c.rating < 4.5) return false;
  return true;
});

const qualifyingIds = qualifyingClasses.map(c => c.id);

// CP2 (0.60): User booked at least one of these qualifying classes with the attendee name 'Sam Evening'
const qualifyingBookings = bookings.filter(b =>
  qualifyingIds.includes(b.liveClassId) &&
  b.attendeeName === 'Sam Evening'
);

checkpoints.push({
  passed: qualifyingBookings.length > 0,
  weight: 0.60
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

// All subscriptions with the correct email and first name
const subsEmailName = subs.filter(s =>
  s.email === 'strength.mobility@example.com' &&
  s.firstName === 'Jordan'
);

// CP1 (0.40): There is a subscription with the correct email and first name
checkpoints.push({
  passed: subsEmailName.length > 0,
  weight: 0.40
});

// CP2 (0.30): Among those, at least one has focusAreas including strength and mobility_flexibility and frequency three_times_per_week
const subsFocusFreq = subsEmailName.filter(s => {
  const focus = Array.isArray(s.focusAreas) ? s.focusAreas : [];
  const hasStrength = focus.includes('strength');
  const hasMobility = focus.includes('mobility_flexibility');
  return hasStrength && hasMobility && s.emailFrequency === 'three_times_per_week';
});

checkpoints.push({
  passed: subsFocusFreq.length > 0,
  weight: 0.30
});

// CP3 (0.30): Among those, at least one has ONLY 'training_tips_workout_reminders' enabled as notificationTopics
const subsTopicsCorrect = subsFocusFreq.filter(s => {
  const topics = Array.isArray(s.notificationTopics) ? s.notificationTopics : [];
  const allowed = 'training_tips_workout_reminders';
  if (!topics.includes(allowed)) return false;
  // Ensure no disallowed topics like promotions or product_updates are enabled
  const disallowed = ['promotions', 'product_updates'];
  const hasDisallowed = topics.some(t => disallowed.includes(t));
  return !hasDisallowed && topics.every(t => t === allowed);
});

checkpoints.push({
  passed: subsTopicsCorrect.length > 0,
  weight: 0.30
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// last FAQ search query (instrumented)
let rawQuery = localStorage.getItem('task8_lastFaqSearchQuery');
let searchQuery = null;
if (rawQuery != null) {
  try {
    searchQuery = JSON.parse(rawQuery);
  } catch (e) {
    searchQuery = rawQuery;
  }
}

const chatSessions = JSON.parse(localStorage.getItem('chat_sessions') || '[]');
const chatMessages = JSON.parse(localStorage.getItem('chat_messages') || '[]');

// CP1 (0.30): Last FAQ search query contains 'pause membership'
let searchedPauseMembership = false;
if (typeof searchQuery === 'string') {
  const q = searchQuery.toLowerCase();
  searchedPauseMembership = q.indexOf('pause membership') !== -1;
}
checkpoints.push({
  passed: searchedPauseMembership,
  weight: 0.30
});

// Identify chat sessions started from the FAQ page
const faqChatSessions = chatSessions.filter(s => s.source === 'faq_page');
const faqChatSessionIds = faqChatSessions.map(s => s.id);

// CP2 (0.30): There is at least one chat session whose source is 'faq_page'
checkpoints.push({
  passed: faqChatSessions.length > 0,
  weight: 0.30
});

// CP3 (0.40): Within an FAQ-page chat session, the user sent the specified question about pausing membership for 2 weeks starting next Monday without losing progress data
const targetPhrase = 'can i pause my membership for 2 weeks starting next monday without losing my progress data?';
const userFaqMessages = chatMessages.filter(m =>
  faqChatSessionIds.includes(m.chatSessionId) &&
  m.senderType === 'user' &&
  typeof m.messageText === 'string'
);

const askedCorrectQuestion = userFaqMessages.some(m => {
  const text = m.messageText.trim().toLowerCase();
  return text.indexOf('pause my membership for 2 weeks starting next monday') !== -1 &&
         text.indexOf('without losing my progress data') !== -1;
});

checkpoints.push({
  passed: askedCorrectQuestion,
  weight: 0.40
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
